namespace Dataphyre\Panel;

/**
 * Emits core layout CSS for the Panel shell.
 *
 * The trait owns static stylesheet blocks for command palette chrome, app frame
 * layout, table containment, action surfaces, relations, and responsive shell
 * behavior. The renderer decides injection order; these methods only return CSS
 * strings and have no request or persistence side effects.
 */
trait PanelRendererAssetsLayoutCoreCss {
	/**
	 * Provides command palette, modal overlay, toast, and notice chrome styles.
	 *
	 * this CSS block is loaded as part of the panel layout foundation so
	 * keyboard-driven navigation and transient feedback share the same theme token
	 * rules as the rest of the shell. It has no runtime side effects beyond the
	 * returned stylesheet string.
	 */
	private static function commandPaletteCss(): string {
		return 'body.dp-panel-command-open{overflow:hidden}.dp-panel-command-root{position:fixed;inset:0;z-index:10000;display:grid;align-items:start;justify-items:center;background:rgba(15,23,42,.48);padding:9vh 18px 18px;backdrop-filter:blur(10px)}.dp-panel-command-root[hidden]{display:none}.dp-panel-command{display:grid;gap:10px;width:min(100%,720px);border:1px solid var(--dp-border);border-radius:calc(var(--dp-radius) + 6px);background:var(--dp-surface);box-shadow:0 28px 80px rgba(15,23,42,.35);padding:12px}.dp-panel-command input{width:100%;border:1px solid var(--dp-control_border);border-radius:calc(var(--dp-radius) + 2px);background:var(--dp-control_bg);color:var(--dp-text);padding:14px 15px;font:inherit;font-size:16px;outline:none}.dp-panel-command input:focus{border-color:var(--dp-primary-600);box-shadow:0 0 0 4px rgba(37,99,235,.12)}.dp-panel-command-list{display:grid;gap:5px;max-height:min(60vh,520px);overflow:auto}.dp-panel-command-group{padding:8px 10px 2px;color:var(--dp-text_soft);font-size:10px;font-weight:900;letter-spacing:.08em;text-transform:uppercase}.dp-panel-command-item{display:grid;gap:3px;width:100%;border:1px solid transparent;border-radius:var(--dp-radius);background:transparent;color:var(--dp-text);padding:10px 12px;text-align:left;text-decoration:none;font:inherit;cursor:pointer}.dp-panel-command-item span{color:var(--dp-text_muted);font-size:11px;font-weight:850;letter-spacing:.04em;text-transform:uppercase}.dp-panel-command-item strong{font-size:14px;font-weight:800;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.dp-panel-command-item:hover,.dp-panel-command-item.active{border-color:var(--dp-border_soft);background:var(--dp-surface_muted);color:var(--dp-primary-700)}.dp-panel-command-empty{margin:0;color:var(--dp-text_muted);padding:18px;text-align:center}.dp-panel-toast-root{position:fixed;right:18px;bottom:18px;z-index:10020;display:grid;gap:10px;width:min(410px,calc(100vw - 28px));pointer-events:none}.dp-panel-toast{display:grid;grid-template-columns:auto minmax(0,1fr) auto auto;gap:10px;align-items:start;transform:translateY(8px);opacity:0;border:1px solid var(--dp-border);border-radius:calc(var(--dp-radius) + 4px);background:var(--dp-surface);color:var(--dp-text);box-shadow:0 18px 44px rgba(15,23,42,.20);padding:12px 13px;font-size:13px;font-weight:760;pointer-events:auto;transition:opacity .18s ease,transform .18s ease}.dp-panel-toast.show{transform:translateY(0);opacity:1}.dp-panel-toast-icon{display:inline-grid;place-items:center;width:26px;height:26px;border-radius:999px;background:var(--dp-neutral_bg);color:var(--dp-neutral_text);font-size:12px;font-weight:950;line-height:1}.dp-panel-toast-copy{display:grid;gap:3px;min-width:0}.dp-panel-toast-copy strong{color:var(--dp-text);font-size:13px;font-weight:900;line-height:1.15}.dp-panel-toast-copy span{color:var(--dp-text_muted);font-size:12px;font-weight:720;line-height:1.35;overflow-wrap:anywhere}.dp-panel-toast a{align-self:center;color:var(--dp-primary-700);font-size:12px;font-weight:900;text-decoration:none;white-space:nowrap}.dp-panel-toast a:hover{text-decoration:underline}.dp-panel-toast button{align-self:start;border:0;border-radius:999px;background:var(--dp-neutral_bg);color:var(--dp-neutral_text);width:24px;height:24px;padding:0;font-size:17px;line-height:1;cursor:pointer}.dp-panel-toast-success{border-color:var(--dp-success-100)}.dp-panel-toast-success .dp-panel-toast-icon{background:var(--dp-success-50);color:var(--dp-success-800)}.dp-panel-toast-warning{border-color:var(--dp-warning-100)}.dp-panel-toast-warning .dp-panel-toast-icon{background:var(--dp-warning-50);color:var(--dp-warning-800)}.dp-panel-toast-error{border-color:var(--dp-danger-100)}.dp-panel-toast-error .dp-panel-toast-icon{background:var(--dp-danger-50);color:var(--dp-danger-800)}.dp-panel-toast-info{border-color:var(--dp-info-100)}.dp-panel-toast-info .dp-panel-toast-icon{background:var(--dp-info-50);color:var(--dp-info-800)}.dp-panel-notice a{justify-self