	}

	/**
	 * Returns the panel application frame and responsive page layout rules.
	 *
	 * this stylesheet establishes the high-level width modes, sidebar
	 * grid, toolbar alignment, filters, table shells, and mobile breakpoints that
	 * every rendered panel page assumes before feature-specific CSS is appended.
	 */
	private static function appFrameCss(): string {
		return <<<'CSS'
html,body{width:100%;min-height:100%;overflow-x:hidden}.dp-panel{width:100%!important;max-width:none!important;margin:0!important;padding:clamp(14px,1.3vw,28px)!important}.dp-panel-page-width-constrained{width:min(100%,var(--dp-page-max,1720px))!important;margin-inline:auto!important}.dp-panel-page-width-fluid{width:100%!important;max-width:none!important;margin-inline:0!important}.dp-panel-page-width-compact{width:min(100%,1280px)!important;margin-inline:auto!important}.dp-panel-with-sidebar{display:grid!important;grid-template-columns:minmax(236px,286px) minmax(0,1fr)!important;grid-auto-rows:max-content!important;column-gap:clamp(16px,1.4vw,28px)!important;align-items:start!important;max-width:none!important}.dp-panel-with-sidebar>*:not(.dp-panel-sidebar){grid-column:2!important;min-width:0}.dp-panel-sidebar{grid-column:1!important;grid-row:1!important}.dp-panel>header{margin:0 0 18px!important}.dp-panel-heading-row{align-items:center!important}.dp-panel-heading-tools{display:flex;align-items:center;justify-content:flex-end;gap:10px;flex-wrap:wrap}.dp-panel-live-control,.dp-panel-theme-toggle{min-height:38px;align-items:center}.dp-panel-custom-page,.dp-panel-page-table,.dp-panel-bulk-form,.dp-panel-form,.dp-panel-show,.dp-panel-record-pulse,.dp-panel-table-pulse,.dp-panel-board-pulse,.dp-panel-form-pulse{width:100%;max-width:none}.dp-panel-widgets{grid-template-columns:repeat(auto-fit,minmax(240px,1fr));align-items:stretch}.dp-panel-grid{grid-template-columns:repeat(auto-fit,minmax(240px,1fr));align-items:stretch}.dp-panel-card,.dp-panel-custom-page>section,.dp-panel-custom-page>article,.dp-panel-page-table,.dp-panel-form-section,.dp-panel-record-heading,.dp-panel-table,.dp-panel-board-column,.dp-panel-summary,.dp-panel-widget{min-width:0}.dp-panel-global-search{display:grid!important;grid-template-columns:minmax(260px,1fr) auto auto;align-items:center!important;gap:10px!important;margin:0 0 18px!important;padding:0!important;border:0!important;background:transparent!important}.dp-panel-global-search input{min-height:44px}.dp-panel-toolbar{display:grid!important;grid-template-columns:minmax(260px,1fr) auto!important;gap:14px!important;align-items:start!important;margin:0 0 14px!important}.dp-panel-toolbar>span:empty{display:none}.dp-panel-toolbar-actions{display:flex!important;align-items:center!important;justify-content:flex-end!important;gap:10px!important;flex-wrap:wrap!important;min-width:0}.dp-panel-toolbar-actions>*{flex:0 0 auto}.dp-panel-search{display:flex!important;align-items:center!important;gap:10px!important;padding:0!important;border:0!important;background:transparent!important;min-width:min(520px,100%)}.dp-panel-search input{min-width:240px;min-height:44px}.dp-panel-per-page label{display:flex!important;align-items:center!important;gap:8px!important;min-height:44px}.dp-panel-per-page select{min-height:44px}.dp-panel-density{min-height:44px;align-items:center}.dp-panel-density a{display:inline-flex;align-items:center;justify-content:center;min-height:36px}.dp-panel-column-picker summary{min-height:44px}.dp-panel-button,.dp-panel-action{min-height:44px;padding:10px 16px}.dp-panel-filters{display:grid!important;grid-template-columns:repeat(4,minmax(160px,1fr))!important;gap:12px!important;align-items:end!important;margin:0 0 14px!important;padding:14px!important}.dp-panel-filter{min-width:0!important;align-self:end}.dp-panel-filter-range{grid-column:span 2}.dp-panel-filter input,.dp-panel-filter select{min-height:44px}.dp-panel-range-controls{display:grid!important;grid-template-columns:repeat(2,minmax(0,1fr))!important;gap:10px!important}.dp-panel-filters>.dp-panel-button,.dp-panel-filters>button,.dp-panel-filters>a{align-self:end}.dp-panel-page-table>header{display:flex!important;align-items:center!important;justify-content:space-between!important;gap:14px!important;margin:0 0 8px!important}.dp-panel-table-shell{width:100%;min-width:0}.dp-panel-table-scroll{width:100%;max-width:100%}.dp-panel-action-group{z-index:40}.dp-panel-action-menu,.dp-panel-column-picker form{z-index:5000!important}.dp-panel-sidebar-link.active{box-shadow:0 8px 20px rgba(37,99,235,.08)!important}.dp-panel-table-views{width:auto;max-width:100%;align-items:center}.dp-panel-table-view{min-height:38px;align-items:center}.dp-panel-live-control [data-dp-panel-live-updated]{white-space:nowrap}@media(min-width:1700px){.dp-panel-widgets{grid-template-columns:repeat(4,minmax(0,1fr))}.dp-panel-grid{grid-template-columns:repeat(4,minmax(0,1fr))}}@media(max-width:1180px){.dp-panel-with-sidebar{display:block!important}.dp-panel-with-sidebar>*:not(.dp-panel-sidebar){grid-column:auto!important}.dp-panel-sidebar{position:relative!important;top:auto!important;max-height:none!important;margin:0 0 18px!important}.dp-panel-toolbar{grid-template-columns:1fr!important}.dp-panel-toolbar-actions{justify-content:flex-start!important}.dp-panel-filters{grid-template-columns:repeat(2,minmax(0,1fr))!important}.dp-panel-filter-range{grid-column:1/-1}}@media(max-width:760px){.dp-panel{padding:12px!important}.dp-panel-global-search,.dp-panel-toolbar,.dp-panel-search{display:grid!important;grid-template-columns:1fr!important}.dp-panel-toolbar-actions{justify-content:stretch!important}.dp-panel-toolbar-actions>.dp-panel-button,.dp-panel-toolbar-actions>.dp-panel-action,.dp-panel-toolbar-actions>.dp-panel-inline-action,.dp-panel-toolbar-actions>.dp-panel-inline-action>.dp-panel-action{width:100%}.dp-panel-filters{grid-template-columns:1fr!important}.dp-panel-filter-range{grid-column:1/-1}.dp-panel-page-table>header{display:grid!important}.dp-panel-heading-row{display:grid!important}.dp-panel-heading-tools{justify-content:flex-start}.dp-panel-live-control{width:100%;overflow:auto}.dp-panel-theme-toggle{width:max-content;max-width:100%;overflow:auto}}
CSS;
	}

	/**
