e:21px}.dp-panel-relation>.dp-panel-toolbar{align-items:center;margin:0}.dp-panel-relation>.dp-panel-toolbar .dp-panel-search{margin:0;flex:1}.dp-panel-relation>.dp-panel-toolbar .dp-panel-search input{min-width:min(360px,70vw)}.dp-panel-relation>.dp-panel-filters{margin:0}.dp-panel-relation>.dp-panel-table-views{margin:0}.dp-panel-relation>.dp-panel-summaries{margin:0}.dp-panel-relation>.dp-panel-table-scroll{border-radius:14px;border:1px solid var(--dp-border_soft);background:var(--dp-surface);overflow:auto}.dp-panel-relation>.dp-panel-table-scroll .dp-panel-table{border:0;border-radius:0;box-shadow:none}body[data-dp-theme-mode="dark"] .dp-panel-relation{background:linear-gradient(180deg,#172234,#111827);border-color:#34445d}body[data-dp-theme-mode="dark"] .dp-panel-relation-meta span{background:#182235;border-color:#34445d;color:#d6deeb}body[data-dp-theme-mode="dark"] .dp-panel-relation-meta strong{background:#20375d;border-color:#3b64a4;color:#e8f1ff}@media(max-width:980px){.dp-panel-relation-header{grid-template-columns:1fr}.dp-panel-relation-aside{justify-items:start;min-width:0}.dp-panel-relation-meta{justify-content:flex-start}.dp-panel-relation-aside .dp-panel-summaries{width:100%}.dp-panel-relation>.dp-panel-toolbar{display:grid}.dp-panel-relation>.dp-panel-toolbar .dp-panel-search{display:grid}.dp-panel-relation>.dp-panel-toolbar .dp-panel-search input{min-width:0}}@media(max-width:560px){.dp-panel-relation{padding:10px;border-radius:16px}.dp-panel-relation-title h2{font-size:19px}.dp-panel-relation-meta{display:grid;grid-template-columns:1fr 1fr;width:100%}.dp-panel-relation-meta span,.dp-panel-relation-meta strong{justify-content:center}.dp-panel-relation-aside .dp-panel-summaries{grid-template-columns:1fr}}
